// Run this query and look at 'totalDocsExamined'
db.books.find({ publishedYear: 1949 }).explain('executionStats')
// totalDocsExamined: 50 (all docs scanned to find 1 result!)
// stage: 'COLLSCAN'

// Single field index (1 = ascending, -1 = descending)
db.books.createIndex({ publishedYear: 1 })

// Now the same query is fast!
db.books.find({ publishedYear: 1949 }).explain('executionStats')
// stage: 'IXSCAN', totalDocsExamined: 1

// Compound index — covers queries on both fields
db.books.createIndex({ authorId: 1, publishedYear: -1 })
// Useful for: find by author, sorted by year descending

// Unique index (like UNIQUE constraint in SQL)
db.authors.createIndex({ email: 1 }, { unique: true })

// Sparse index — only indexes documents where the field exists
db.books.createIndex({ promoCode: 1 }, { sparse: true })

// List all indexes on a collection
db.books.getIndexes()

// Drop an index
db.books.dropIndex({ publishedYear: 1 })

// Create a text index
db.books.createIndex({ title: 'text', tags: 'text' })

// Search using $text
db.books.find({ $text: { $search: 'dystopia surveillance' } })

// Sort by relevance score
db.books.find(
  { $text: { $search: 'dystopia' } },
  { score: { $meta: 'textScore' } }
).sort({ score: { $meta: 'textScore' } })

db.books.find({ genres: 'fiction', price: { $lt: 15 } }).explain('executionStats')

// Key fields to look at:
// executionStats.totalDocsExamined  → rows read (want this LOW)
// executionStats.nReturned          → rows returned
// executionStats.executionTimeMillis → query time
// queryPlanner.winningPlan.stage    → COLLSCAN (bad) or IXSCAN (good)

// Ideal: totalDocsExamined ≈ nReturned
// Terrible: totalDocsExamined = 50, nReturned = 1 → missing index

// Create an index that includes both the filter field and the projected fields
db.books.createIndex({ authorId: 1, title: 1 })

// This query is COVERED — all data comes from the index, zero document reads
db.books.find(
  { authorId: ObjectId('...') },         // filter: authorId is in the index
  { title: 1, _id: 0 }                   // project: title is in the index, exclude _id
).explain('executionStats')
// totalDocsExamined: 0  ← never touches the actual documents!

// Only index orders with status 'active' — ignore delivered/cancelled
db.orders.createIndex(
  { orderedAt: -1 },
  { partialFilterExpression: { status: 'active' } }
)

// This index is used for queries that include status: 'active'
db.orders.find({ status: 'active', orderedAt: { $gt: ISODate('...') } })
// Much smaller index than indexing all orders
